#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int fa[N],n,m,need;
struct node
{
	int s,t,v,c;
	bool operator<(const node other)
	{
		if(v==other.v) return c<other.c;
		else return v<other.v;
	}
} g[N];
int find(int x)
{
	if(fa[x]==x) return x;
	return fa[x]=find(fa[x]);
}
int sum,ans,cntwhite,cnt;
void kruskal()
{
	sort(g+1,g+1+m);
	for(int i=1;cnt<n-1;i++)
	{
		int fs=find(g[i].s),ft=find(g[i].t);
		if(fs==ft) continue;
		cnt++;
		fa[fs]=ft;
		if(g[i].c==0) cntwhite++;
		sum+=g[i].v;
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>need;
	for(int i=1;i<=m;i++)
	{
		cin>>g[i].s>>g[i].t>>g[i].v>>g[i].c;
		g[i].s++,g[i].t++;
	}
	int l=-100,r=100;
	while(l<=r)
	{
		int mid=(l+r)/2;
		for(int i=1;i<=m;i++)
		{
			if(g[i].c==0) g[i].v+=mid;
		}
		for(int i=1;i<=n;i++) fa[i]=i;
		sum=0,cnt=0,cntwhite=0;
		kruskal();
		if(cntwhite>=need)
		{
			l=mid+1;
			ans=sum-need*mid;
		}
		else r=mid-1;
		for(int i=1;i<=m;i++)
		{
			if(g[i].c==0) g[i].v-=mid;
		}
	}
	cout<<ans;
	return 0;
}
